section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/devops-lb-algorithms.json",
  "title": "Load Balancer Types and Algorithm Selection",
  "type": "object",
  "required": [
    "layer",
    "algorithm",
    "session_affinity",
    "rationale",
    "backends",
    "owner",
    "last_reviewed"
  ],
  "properties": {
    "layer": {
      "enum": [
        "L4",
        "L7",
        "DNS",
        "Global"
      ]
    },
    "algorithm": {
      "enum": [
        "round_robin",
        "weighted_round_robin",
        "least_connections",
        "weighted_least_connections",
        "ip_hash",
        "least_response_time",
        "random",
        "consistent_hashing"
      ]
    },
    "session_affinity": {
      "enum": [
        "none",
        "cookie",
        "consistent_hash_key",
        "ip_hash"
      ]
    },
    "rationale": {
      "type": "string",
      "minLength": 50
    },
    "backends": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": [
          "host",
          "weight"
        ]
      }
    },
    "owner": {
      "type": "string"
    },
    "last_reviewed": {
      "type": "string"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "layer": "L7",
  "algorithm": "weighted_least_connections",
  "session_affinity": "cookie",
  "rationale": "API backend with heterogeneous instance sizes and long-lived WebSocket connections; least-conn rebalances under variance while weights match measured RPS capacity.",
  "backends": [
    {
      "host": "api1.internal",
      "weight": 100
    },
    {
      "host": "api2.internal",
      "weight": 100
    },
    {
      "host": "api3.internal",
      "weight": 50
    }
  ],
  "owner": "sre@acme.io",
  "last_reviewed": "2026-05-23"
}
